<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>2048</title>
  <style>
    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      background: #121214;
      color: #e0e0e0;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
    }

    .game-container {
      text-align: center;
    }

    h1 {
      margin: 0 0 0.5rem;
      font-size: 2.5rem;
      color: #ffffff;
    }

    .controls {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 1rem;
      margin-bottom: 1.25rem;
      font-size: 1.1rem;
    }

    #score {
      font-weight: bold;
      color: #f9f9f9;
    }

    #reset {
      background: #3c3c3e;
      color: #fff;
      border: none;
      padding: 0.5rem 1rem;
      border-radius: 0.4rem;
      cursor: pointer;
      font-size: 1rem;
      transition: background 0.15s;
    }

    #reset:hover {
      background: #4f4f52;
    }

    #board {
      display: grid;
      grid-template-columns: repeat(4, 80px);
      grid-template-rows: repeat(4, 80px);
      gap: 10px;
      background: #1e1e20;
      padding: 10px;
      border-radius: 8px;
      box-shadow: 0 4px 24px rgba(0, 0, 0, 0.55);
    }

    .tile {
      width: 80px;
      height: 80px;
      background: #2a2a2c;
      border-radius: 6px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 1.6rem;
      font-weight: bold;
      color: #fff;
      transition: background 0.15s, transform 0.1s;
    }

    .tile.empty {
      color: transparent;
      background: #2a2a2c;
    }

    .value-2    { background: #3b3b3e; color: #d1d1d1; }
    .value-4    { background: #4a4a4d; color: #e8e8e8; }
    .value-8    { background: #f2b179; }
    .value-16   { background: #f59563; }
    .value-32   { background: #f67c5f; }
    .value-64   { background: #f65e3b; }
    .value-128  { background: #edcf72; font-size: 1.4rem; }
    .value-256  { background: #edcc61; font-size: 1.4rem; }
    .value-512  { background: #edc850; font-size: 1.4rem; }
    .value-1024 { background: #edc53f; font-size: 1.2rem; }
    .value-2048 { background: #edc22e; font-size: 1.2rem; }
    .value-4096,
    .value-8192,
    .value-16384,
    .value-32768,
    .value-65536 { background: #3c3a32; font-size: 1.1rem; }
  </style>
</head>
<body>
  <div class="game-container">
    <h1>2048</h1>
    <div class="controls">
      <div>Score: <span id="score">0</span></div>
      <button id="reset">New Game</button>
    </div>
    <div id="board"></div>
  </div>

  <script>
    (function () {
      const SIZE = 4;
      let grid = [];
      let currentScore = 0;

      const boardEl = document.getElementById("board");
      const scoreEl = document.getElementById("score");
      const resetEl = document.getElementById("reset");

      function createEmptyGrid() {
        return Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
      }

      function cloneGrid(g) {
        return g.map(row => row.slice());
      }

      function gridsEqual(a, b) {
        for (let r = 0; r < SIZE; r++) {
          for (let c = 0; c < SIZE; c++) {
            if (a[r][c] !== b[r][c]) return false;
          }
        }
        return true;
      }

      function getEmptyCells() {
        const cells = [];
        for (let r = 0; r < SIZE; r++) {
          for (let c = 0; c < SIZE; c++) {
            if (grid[r][c] === 0) cells.push({ r, c });
          }
        }
        return cells;
      }

      function addRandomTile() {
        const empties = getEmptyCells();
        if (empties.length === 0) return;
        const idx = Math.floor(Math.random() * empties.length);
        const { r, c } = empties[idx];
        grid[r][c] = Math.random() < 0.9 ? 2 : 4;
      }

      function render() {
        const cells = boardEl.children;
        for (let r = 0; r < SIZE; r++) {
          for (let c = 0; c < SIZE; c++) {
            const val = grid[r][c];
            const cell = cells[r * SIZE + c];
            cell.textContent = val || "";
            cell.className = "tile" + (val ? ` value-${val}` : " empty");
          }
        }
        scoreEl.textContent = currentScore;
      }

      function initBoard() {
        boardEl.innerHTML = "";
        for (let i = 0; i < SIZE * SIZE; i++) {
          const cell = document.createElement("div");
          cell.className = "tile empty";
          boardEl.appendChild(cell);
        }
      }

      function resetGame() {
        grid = createEmptyGrid();
        currentScore = 0;
        addRandomTile();
        addRandomTile();
        render();
      }

      function extractVector(direction, index) {
        if (direction === "left") return grid[index].slice();
        if (direction === "right") return grid[index].slice().reverse();
        if (direction === "up") {
          return [grid[0][index], grid[1][index], grid[2][index], grid[3][index]];
        }
        // down
        return [grid[3][index], grid[2][index], grid[1][index], grid[0][index]];
      }

      function writeVector(direction, index, vector) {
        if (direction === "left") {
          grid[index] = vector.slice();
        } else if (direction === "right") {
          grid[index] = vector.slice().reverse();
        } else if (direction === "up") {
          for (let r = 0; r < SIZE; r++) grid[r][index] = vector[r];
        } else {
          for (let r = 0; r < SIZE; r++) grid[3 - r][index] = vector[r];
        }
      }

      function slideAndMerge(line) {
        let arr = line.filter(v => v !== 0);
        let gained = 0;
        for (let i = 0; i < arr.length - 1; i++) {
          if (arr[i] === arr[i + 1]) {
            arr[i] *= 2;
            gained += arr[i];
            arr[i + 1] = 0;
            i++; // prevent double-merge
          }
        }
        arr = arr.filter(v => v !== 0);
        while (arr.length < SIZE) arr.push(0);
        return { result: arr, score: gained };
      }

      function move(direction) {
        const previous = cloneGrid(grid);
        let scoreGained = 0;

        for (let i = 0; i < SIZE; i++) {
          const vector = extractVector(direction, i);
          const { result, score } = slideAndMerge(vector);
          scoreGained += score;
          writeVector(direction, i, result);
        }

        if (gridsEqual(grid, previous)) {
          return false;
        }

        currentScore += scoreGained;
        addRandomTile();
        render();
        return true;
      }

      function setBoard(arr) {
        grid = cloneGrid(arr);
        currentScore = 0;
        render();
      }

      function getBoard() {
        return cloneGrid(grid);
      }

      function getScore() {
        return currentScore;
      }

      window.game = {
        size: SIZE,
        reset: resetGame,
        move: move,
        board: getBoard,
        setBoard: setBoard,
        score: getScore
      };

      document.addEventListener("keydown", (e) => {
        const map = {
          ArrowLeft: "left",
          ArrowRight: "right",
          ArrowUp: "up",
          ArrowDown: "down"
        };
        if (map[e.key]) {
          e.preventDefault();
          move(map[e.key]);
        }
      });

      resetEl.addEventListener("click", resetGame);

      initBoard();
      resetGame();
    })();
  </script>
</body>
</html>
